static int parse_int_param(const char *s, int def) {
    if (!s || !*s) return def;
    char *end = NULL;
    long v = strtol(s, &end, 10);
    if (!end || *end != '\0') return def;
    if (v < 0) v = 0;
    if (v > 1000000000L) v = 1000000000L;
    return (int)v;
}

static int is_blank(const char *s) {
    if (!s) return 1;
    for (const unsigned char *p = (const unsigned char *)s; *p; p++) {
        if (*p != ' ' && *p != '\t' && *p != '\n' && *p != '\r') return 0;
    }
    return 1;
}

static char *json_get_string_dup(const char *json, const char *key) {
    if (!json || !key) return NULL;
    char needle[128];
    snprintf(needle, sizeof(needle), "\"%s\"", key);
    const char *p = strstr(json, needle);
    if (!p) return NULL;
    p += strlen(needle);
    while (*p && (*p == ' ' || *p == '\t' || *p == '\r' || *p == '\n')) p++;
    if (*p != ':') return NULL;
    p++;
    while (*p && (*p == ' ' || *p == '\t' || *p == '\r' || *p == '\n')) p++;
    if (*p != '"') return NULL;
    p++;

    size_t cap = 64, len = 0;
    char *out = malloc(cap);
    if (!out) return NULL;

    while (*p) {
        if (*p == '"') {
            out[len] = '\0';
            return out;
        }
        if (*p == '\\') {
            p++;
            if (!*p) break;
            char c = *p;
            switch (c) {
                case '"': c = '"'; break;
                case '\\': c = '\\'; break;
                case '/': c = '/'; break;
                case 'b': c = '\b'; break;
                case 'f': c = '\f'; break;
                case 'n': c = '\n'; break;
                case 'r': c = '\r'; break;
                case 't': c = '\t'; break;
                default: break;
            }
            if (len + 2 > cap) {
                cap *= 2;
                char *nb = realloc(out, cap);
                if (!nb) { free(out); return NULL; }
                out = nb;
            }
            out[len++] = c;
            p++;
            continue;
        }
        if (len + 2 > cap) {
            cap *= 2;
            char *nb = realloc(out, cap);
            if (!nb) { free(out); return NULL; }
            out = nb;
        }
        out[len++] = *p;
        p++;
    }
    free(out);
    return NULL;
}

