static int parse_int_param(const char *s, int def) {
    if (!s || !*s) return def;
    char *end = NULL;
    long v = strtol(s, &end, 10);
    if (!end || *end != '\0') return def;
    if (v < 0) v = 0;
    if (v > 1000000000L) v = 1000000000L;
    return (int)v;
}

static int is_blank(const char *s) {
    if (!s) return 1;
    for (const unsigned char *p = (const unsigned char *)s; *p; p++) {
        if (*p != ' ' && *p != '\t' && *p != '\n' && *p != '\r') return 0;
    }
    return 1;
}

static char *json_get_string_dup(const char *json, const char *key) {
    if (!json || !key) return NULL;
    char needle[128];
    snprintf(needle, sizeof(needle), "\"%s\"", key);
    const char *p = strstr(json, needle);
    if (!p) return NULL;
    p += strlen(needle);
    while (*p && (*p == ' ' || *p == '\t' || *p == '\r' || *p == '\n')) p++;
    if (*p != ':') return NULL;
    p++;
    while (*p && (*p == ' ' || *p == '\t' || *p == '\r' || *p == '\n')) p++;
    if (*p != '"') return NULL;
    p++;

    size_t cap = 64, len = 0;
    char *out = malloc(cap);
    if (!out) return NULL;

    while (*p) {
        if (*p == '"') {
            out[len] = '\0';
            return out;
        }
        if (*p == '\\') {
            p++;
            if (!*p) break;
            char c = *p;
            switch (c) {
                case '"': c = '"'; break;
                case '\\': c = '\\'; break;
                case '/': c = '/'; break;
                case 'b': c = '\b'; break;
                case 'f': c = '\f'; break;
                case 'n': c = '\n'; break;
                case 'r': c = '\r'; break;
                case 't': c = '\t'; break;
                default: break;
            }
            if (len + 2 > cap) {
                cap *= 2;
                char *nb = realloc(out, cap);
                if (!nb) { free(out); return NULL; }
                out = nb;
            }
            out[len++] = c;
            p++;
            continue;
        }
        if (len + 2 > cap) {
            cap *= 2;
            char *nb = realloc(out, cap);
            if (!nb) { free(out); return NULL; }
            out = nb;
        }
        out[len++] = *p;
        p++;
    }
    free(out);
    return NULL;
}

static enum MHD_Result unauthorized(struct MHD_Connection *connection) {
    return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
}

static enum MHD_Result too_large(struct MHD_Connection *connection) {
    return send_json(connection, "{\"error\":\"payload too large\"}", MHD_HTTP_REQUEST_ENTITY_TOO_LARGE);
}

static enum MHD_Result bad_request(struct MHD_Connection *connection) {
    return send_json(connection, "{\"error\":\"bad request\"}", MHD_HTTP_BAD_REQUEST);
}

static int parse_id(const char *url) {
    const char *p = "/api/notes/";
    size_t n = strlen(p);
    if (strncmp(url, p, n) != 0) return -1;
    const char *idstr = url + n;
    if (!*idstr) return -1;
    char *end = NULL;
    long v = strtol(idstr, &end, 10);
    if (!end || *end != '\0') return -1;
    if (v < 0 || v > 2147483647L) return -1;
    return (int)v;
}

enum MHD_Result route_request(struct MHD_Connection *connection, const char *url,
                              const char *method, const char *upload_data,
                              size_t *upload_data_size, void **con_cls) {
    // First call: allocate per-connection storage and return immediately.
    if (*con_cls == NULL) {
        struct connection_info *ci = calloc(1, sizeof(*ci));
        if (!ci) return MHD_NO;
        *con_cls = ci;
        return MHD_YES;
    }

    if (strcmp(method, "OPTIONS") == 0)
        return send_json(connection, "", MHD_HTTP_OK);

    int is_write = (strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0 || strcmp(method, "DELETE") == 0);
    if (is_write && !api_key_valid(connection))
        return unauthorized(connection);

    // Upload handling for POST/PUT
    if ((strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0) && *upload_data_size) {
        struct connection_info *ci = *con_cls;
        if (ci->data_size + *upload_data_size > NOTES_MAX_BODY_BYTES) {
            *upload_data_size = 0;
            return too_large(connection);
        }
        char *nb = realloc(ci->data, ci->data_size + *upload_data_size + 1);
        if (!nb) return MHD_NO;
        ci->data = nb;
        memcpy(ci->data + ci->data_size, upload_data, *upload_data_size);
        ci->data_size += *upload_data_size;
        ci->data[ci->data_size] = '\0';
        *upload_data_size = 0;
        return MHD_YES;
    }

    // Routes
    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "GET") == 0) {
        const char *limit_s = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "limit");
        const char *offset_s = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "offset");
        int limit = parse_int_param(limit_s, NOTES_DEFAULT_PAGE_SIZE);
        int offset = parse_int_param(offset_s, 0);
        if (limit > NOTES_MAX_PAGE_SIZE) limit = NOTES_MAX_PAGE_SIZE;

        int total = get_total_notes_count();
        char *json = get_notes_paginated_json(limit, offset);
        if (!json)
            return send_json_total(connection, "[]", MHD_HTTP_OK, total);
        enum MHD_Result r = send_json_total(connection, json, MHD_HTTP_OK, total);
        free(json);
        return r;
    }

    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "POST") == 0) {
        struct connection_info *ci = *con_cls;
        const char *body = (ci && ci->data) ? ci->data : "";
        char *title = json_get_string_dup(body, "title");
        char *content = json_get_string_dup(body, "content");
        if (!title || is_blank(title)) {
            free(title);
            free(content);
            return bad_request(connection);
        }
        if (!content) content = strdup("");

        int id = create_note(title, content);
        free(title);
        free(content);
        if (id < 0)
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);

        char *obj = get_note_json(id);
        if (!obj)
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        enum MHD_Result r = send_json(connection, obj, MHD_HTTP_CREATED);
        free(obj);
        return r;
    }

    int id = parse_id(url);

    if (id >= 0 && strcmp(method, "GET") == 0) {
        char *obj = get_note_json(id);
        if (!obj) return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        enum MHD_Result r = send_json(connection, obj, MHD_HTTP_OK);
        free(obj);
        return r;
    }

    if (id >= 0 && strcmp(method, "PUT") == 0) {
        if (!note_exists(id))
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);

        struct connection_info *ci = *con_cls;
        const char *body = (ci && ci->data) ? ci->data : "";
        char *title = json_get_string_dup(body, "title");
        char *content = json_get_string_dup(body, "content");
        if (!title || is_blank(title)) {
            free(title);
            free(content);
            return bad_request(connection);
        }
        if (!content) content = strdup("");

        int rc = update_note(id, title, content);
        free(title);
        free(content);
        if (rc < 0)
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        if (rc == 0)
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);

        char *obj = get_note_json(id);
        if (!obj)
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        enum MHD_Result r = send_json(connection, obj, MHD_HTTP_OK);
        free(obj);
        return r;
    }

    if (id >= 0 && strcmp(method, "DELETE") == 0) {
        int rc = delete_note(id);
        if (rc < 0)
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        if (rc == 0)
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        return send_json(connection, "{\"status\":\"deleted\"}", MHD_HTTP_OK);
    }

    return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
}
